rss.channel:
{{ config.title }}
{{ config.base_url }}
{{ config.description }}
{%- for page in pages %}


    {{ page.title }}
    {{ page.permalink }}
    {{ page.date | date(format="%a, %d %b %Y %H:%M:%S %z") }}
    {{ config.author }}
    {{ page.permalink }}

        {% set content = page.content | replace(from="[<em>", to="<u><em>") | replace(from="</em>]", to="</em></u>") %}
        {{ content | safe }}
        <p><br><i>You're awesome for reading this via RSS.</i></p>


{%- endfor %}
